VALUES
  ('social-worker-moex-05860', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關三角檢證（triangulation）的敘述，何者錯誤？', '["由多元視角檢證事物，以提高準確性（accuracy）", "由多元理論觀點來設計研究或解釋資料，被稱為理論三角檢證（triangulation of theory）", "由不同時間來蒐集研究資料，被稱為資料三角檢證（triangulation of data）", "以不同工具測量同一現象，被稱為測量三角檢證（triangulation of measure）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05861', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在運用紮根理論時，編碼過程常會使用到製作備忘錄（memoing）的技術，下列敘述何者錯誤？', '["分析註記（analytical notes）：記錄可能的分析概念、方向、主題", "代碼註記（code notes）：功能在於確認代碼標籤（code label）及其意義", "理論註記（theoretical notes）：記錄內容一般包括概念面向與深層意義反思、概念間關係、理論命題等", "操作註記（operational notes）：主要是處理方法論議題，例如關注資料蒐集情境，這可能攸關日後對資 料的理解"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05862', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對質性個案研究（qualitative case study）的敘述，何者正確？', '["個案研究不必抽樣", "個案研究的樣本數不宜超過3個", "個案研究都是歸納式（induction-based）研究", "個案研究相當適合用來發展新的理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05863', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '小明在撰寫其質性研究的研究報告時，特別將其研究對象的背景資訊予以模糊化，以免讀者從閱讀中即 可獲悉研究對象的身分。小明是恪遵下列那項研究倫理？', '["尊重當事人意願", "給予公平合理的對待", "不欺瞞", "匿名"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05864', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '如果社工人員小瑄遵循「徵詢研究對象的同意（informed consent）」這項研究倫理來進行研究，下列那 件事不是小瑄對研究對象應該做的事？', '["簡介研究目的與程序，包括預期的研究期程", "詳述參與研究的權利與義務，並說明退出後對研究的傷害", "對於研究過程中的匿名性與保密性提出保證", "說明可以隨時退出研究且不會受罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05865', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'essay', '要完成一項研究需要有詳實的規劃，做為進行研究之依據。因此，請詳述一份完整
的研究計畫書應該包含那些內容？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05866', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'essay', '問卷是進行調查研究時重要的研究工具，請詳述當研究者進行設計一份問卷時，應
該遵守那些原則？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05867', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者觀察發現某市某區某家戶的成員支持A政黨，作出該市所有區域內的家戶皆支持A政黨之結論， 此種謬誤稱為： 化約論  套套邏輯  月暈效應  目的論', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05868', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '對於操作型定義的敘述，下列何者錯誤？ 操作型定義是指當界定概念或變項時，直接描述該被界定項的性質或特徵，不需考慮該界定項所作的 操作活動 操作型定義是可具體測量的變項定義 變項的操作型定義，較適用於量化研究 量化研究在進行測量之前，需先想好將會使用的統計方法，避免資料蒐集完成卻無法分析', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05869', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '對於焦點團體的描述和實施，下列敘述何者錯誤？ 相較於個別式深度訪談，可以蒐集更多資料 研究議題較敏感或涉及個人隱私時，可使用焦點團體蒐集資料 主持人最好是傾聽者和議題引導者 如果可以，最好篩選同質性、相容性和互補性高的成員參與討論', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "90e183535e49", "answer_pdf_sha1": "da9b90c792c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
